sys_security_acl.script:
var user = gs.getUser();
var assignment_group = current.getValue('assignment_group') || '';
var primary_office = current.getValue('primary_office') || '';
var allow = false;
if(assignment_group == '' || user.isMemberOf(current.assignment_group.name.toString())){
	allow = true;
}
else{
	allow = new task_privacy().userCanAccessOU(primary_office);
}
answer = allow;
